/*
<!-- Variable definitions -->
<Variable name="keycolor" description="Main Color" type="color" default="$(main.color)" value="#1967D2"/>
<Variable name="followByEmail" description="Follow By Email Text" type="string" default="Get all latest content delivered straight to your inbox." value="Get all latest content delivered straight to your inbox."/>

<Group description="Theme Colors" selector="body">
 <Variable name="main.color" description="Theme Color" type="color" default="#1967D2" value="#1967D2"/>
  <Variable name="main.dark.color" description="Dark Color" type="color" default="#1f2024" value="#1f2024"/>
  <Variable name="header.bg" description="Header Background" type="color" default="#ffffff" value="#ffffff"/>
  <Variable name="menu.color" description="Menu Color" type="color" default="#202124" value="#202124"/>
  <Variable name="submenu.bg" description="SubMenu Background" type="color" default="#fefefe" value="#fefefe"/>
  <Variable name="submenu.color" description="SubMenu Color" type="color" default="#202124" value="#202124"/>
  <Variable name="title.color" description="Title Color" type="color" default="#202124" value="#202124"/>
  <Variable name="widget.title" description="Widget Title Color" type="color" default="#202124" value="#202124"/>
</Group>

<Group description="Theme Body" selector="body">
  <Variable name="body.background.color" description="Body Background Color" type="color" default="#f7f7ff"  value="#f7f7ff"/>
  <Variable name="body.background" description="Background" type="background" color="$(body.background.color)" default="$(color) url() repeat fixed top left" value="$(color) url() repeat fixed top left"/>
  <Variable name="body.text.color" description="Text Color" type="color" default="#656565"  value="#656565"/>
  <Variable name="body.link.color" description="Link Color" type="color" default="$(main.color)"  value="#1967D2"/>
</Group>
 <Group description="Intro Section" selector="#main-intro">
  <Variable name="intro.title" description="Intro Title Color" type="color" default="#202124" value="#202124"/>
  <Variable name="intro.hg" description="Intro Title Highlight" type="color" default="#1967D2" value="#1967D2"/>
  <Variable name="intro.text" description="Intro Text Color" type="color" default="#2B3154" value="#2B3154"/>
</Group>

<!-- Extra Variables -->
<Variable name="body.text.font" description="Font" hideEditor="true" type="font" default="13px Open Sans, sans-serif"  value="13px Open Sans, sans-serif"/>
<Variable name="posts.background.color" description="Post background color" hideEditor="true" type="color" default="#ffffff"  value="#ffffff"/>
<Variable name="tabs.font" description="Font 2" hideEditor="true" type="font" default="13px Open Sans, sans-serif"  value="13px Open Sans, sans-serif"/>
<Variable name="posts.title.color" description="Post title color" hideEditor="true" type="color" default="#000000"  value="#000000"/>
<Variable name="posts.text.color" description="Post text color" hideEditor="true" type="color" default="#656565"  value="#656565"/>
<Variable name="posts.icons.color" description="Post icons color" hideEditor="true" type="color" default="$(main.color)"  value="#3c5a98"/>
<Variable name="labels.background.color" description="Label background color" hideEditor="true" type="color" default="$(main.color)"  value="#3c5a98"/>
*/

/*-- Reset CSS --*/
#google_translate_element { clear: both; }.thread-expanded .thread-count a { display: none; }.comments .continue { display: none!important; }
.CSS_LIGHTBOX{z-index:999999!important}.CSS_LIGHTBOX_ATTRIBUTION_INDEX_CONTAINER .CSS_HCONT_CHILDREN_HOLDER > .CSS_LAYOUT_COMPONENT.CSS_HCONT_CHILD:first-child > .CSS_LAYOUT_COMPONENT{opacity:0}a,abbr,acronym,address,applet,b,big,blockquote,body,caption,center,cite,code,dd,del,dfn,div,dl,dt,em,fieldset,font,form,h1,h2,h3,h4,h5,h6,html,i,iframe,img,ins,kbd,label,legend,li,object,p,pre,q,s,samp,small,span,strike,strong,sub,sup,table,tbody,td,tfoot,th,thead,tr,tt,u,ul,var{
    padding:0;
    border:0;
    outline:0;
    vertical-align:baseline;
    background:0 0;
    text-decoration:none
}
form,textarea,input,button{
    -webkit-appearance:none;
    -moz-appearance:none;
    appearance:none;
    border-radius:0
}
dl,ul{
    list-style-position:inside;
    font-weight:400;
    list-style:none
}
ul li{
    list-style:none
}
caption,th{
    text-align:center
}
img{
    border:none;
    position:relative
}
a,a:visited{
    text-decoration:none
}
.clearfix{
    clear:both
}
.section,.widget,.widget ul{
    margin:0;
    padding:0
}
a{
    color:$(body.link.color)
}
a:visited {
color:blue;
}
a img{
    border:0
}
abbr{
    text-decoration:none
}
.CSS_LIGHTBOX{
    z-index:999999!important
}
.separator a{
    clear:none!important;
    float:none!important;
    margin-left:0!important;
    margin-right:0!important
}
#navbar-iframe,.widget-item-control,a.quickedit,.home-link,.feed-links{
    display:none!important
}
.error_page #content-wrapper {
    display: block;
}
.center{
    display:table;
    margin:0 auto;
    position:relative
}
.widget > h2,.widget > h3{
    display:none
}
/*-- Body Content CSS --*/
 body{
    background:$(body.background);
    background-color:$(body.background.color);
    font-family:'Open Sans',sans-serif;
    font-size:14px;
    font-weight:400;
    color:$(body.text.color);
    word-wrap:break-word;
    margin:0;
    padding:0
}
 h1,h2,h3,h4,h5,h6{
    font-family: 'Poppins', sans-serif;
}
 #outer-wrapper{
    margin:0 auto;
    background-color:#ffffff;
    box-shadow:0 0 5px rgba(0,0,0,.1)
}
 .row{
    width:1430px
}
 #content-wrapper{
    margin:40px auto 0;
   overflow: visible;
}
.index #content-wrapper{
    display: flex;
}
 #content-wrapper > .container{
    margin:0;
width:100%;
}
 #main-wrapper{
    float:left;
    overflow:hidden;
    width:calc(100% - 375px);
    box-sizing:border-box;
    word-wrap:break-word;
    padding:0;
    margin:0
}
 #sidebar-wrapper{
    float:right;
    overflow:hidden;
    width:340px;
    box-sizing:border-box;
    word-wrap:break-word;
    padding:0
}
 .post-image-wrap{
    position:relative;
    display:block
}
 .post-image-link,.about-author .avatar-container,.comments .avatar-image-container{
    background-color:rgba(155,155,155,0.07);
    color:transparent!important
}

.post-thumb{
    display:block;
    position:relative;
    width:100%;
    height:100%;
    object-fit:cover;
    z-index:1;
    transition:opacity .17s ease,transform .17s ease
}
 .post-image-link:hover .post-thumb,.post-image-wrap:hover .post-image-link .post-thumb{
    opacity:.9
}
 .post-title a{
    display:block
}
 .social a:before{
    display:inline-block;
    font-family:FontAwesome;
    font-style:normal;
    font-weight:400
}
