 #header-wrap{
    position:relative;
    width:100%;
    height:70px;
    background-color:$(header.bg);
    z-index:1010;
    box-shadow:0 1px 4px 0 rgba(0,0,0,0.1);
border-bottom: 1px solid #eee;
}
 #header-wrap .container{
    position:relative;
    margin:0 auto
}
 .header-logo{
    float:left;
    margin:0 20px 0 0
}
 .main-logo{
    position:relative;
    float:left;
    width:auto;
    max-width:250px;
    max-height:52px;
    margin:0;
        padding: 9px 5px;
box-sizing:border-box;
}
 .main-logo .header-image-wrapper{
    display:block
}
 .main-logo img{
    max-width:100%;
    max-height:52px;
    margin:0
}
 .main-logo h1, .main-logo h1 a{
    color:$(main.dark.color);
    font-size:20px;
    line-height:52px;
    margin:0
}
 .main-logo p{
    font-size:12px;
    margin:5px 0 0;
display:none;
}
 .header-menu{
    float:left
}
 #main-menu .widget,#main-menu .widget > h3{
    display:none
}
 #main-menu .show-menu{
    display:block
}
 #main-menu{
    position:relative;
    height:70px;
    z-index:15
}
 #main-menu ul > li{
    float:left;
    position:relative;
    margin:0;
    padding:0;
    transition:background .17s ease
}
 #main-menu ul > li > a{
    position:relative;
    color:$(menu.color);
    font-size:14px;
    font-weight:600;
    line-height:70px;
    display:inline-block;
    text-decoration:none;
    margin:0;
    padding:0 15px;
    transition:color .17s ease
}
 #main-menu ul#main-menu-nav > li:hover{
    background-color:rgba(255,255,255,0.05)
}
 #main-menu ul#main-menu-nav > li:hover > a{
    color:$(menu.color)
}
 #main-menu ul > li > ul{
    position:absolute;
    float:left;
    left:0;
    top:70px;
    width:180px;
    background-color:$(submenu.bg);
    z-index:99999;
    margin-top:0;
    padding:0;
    border:1px solid $(submenu.bg);
    box-shadow:0 2px 2px rgba(0,0,0,0.2);
    visibility:hidden;
    opacity:0
}
 #main-menu ul > li > ul > li > ul{
    position:absolute;
    float:left;
    top:0;
    left:100%;
    margin:-1px 0 0
}
 #main-menu ul > li > ul > li{
    display:block;
    float:none;
    position:relative;
    background-color:rgba(255,255,255,0.03);
    border-bottom:1px solid $(submenu.bg);
    transition:background .17s ease
}
 #main-menu ul > li > ul > li a{
    display:block;
    height:36px;
    font-size:13px;
    color:$(submenu.color);
    font-weight:600;
    line-height:36px;
    box-sizing:border-box;
    margin:0;
    padding:0 15px;
    transition:color .17s ease
}
 #main-menu ul > li > ul > li:last-child{
    border-bottom:0
}
 #main-menu ul > li.has-sub > a:after{
    content:'\f107';
    float:right;
    font-family:FontAwesome;
    font-size:12px;
    font-weight:400;
    margin:0 0 0 6px
}
 #main-menu ul > li > ul > li.has-sub > a:after{
    content:'\f105';
    float:right;
    margin:0
}
 #main-menu ul > li > ul > li a:hover{
    color:$(main.color)
}
 #main-menu ul > li:hover > ul,#main-menu ul > li > ul > li:hover > ul{
    visibility:visible;
    opacity:1
}
 #main-menu ul ul{
    transition:all .17s ease
}
.social-toggle{
    font-family:FontAwesome;
}
 .social-toggle:before{
    content:"\f1e0"
}
 .social-active .social-toggle:before{
    content:"\f00d"
}
 #social-menu{
    display:none;
    position:absolute;
    width:100%;
    height:70px;
    top:0;
    left:0;
    background-color:$(header.bg);
    text-align:center;
    z-index:15;
    margin:0
}
 .social-menu .social li{
    display:inline-block;
    padding:0;
    margin:0
}
 .social-menu .social li a{
    display:block;
    height:70px;
    font-size:14px;
    color:$(menu.color);
    line-height:70px;
    padding:0 10px;
    margin:0 5px;
    transition:color .17s ease
}
 .social-toggle,.show-search,.hide-search{
    position:absolute;
    top:0;
    right:0;
    display:block;
    width:58px;
    height:70px;
    background-color:rgba(255,255,255,0.05);
    line-height:70px;
    z-index:20;
    color:$(menu.color);
    font-size:16px;
    font-weight:400;
    text-align:center;
    cursor:pointer;
    transition:color .17s ease
}
.social-toggle {
    right: 58px;
}
.home .social-toggle {
    right: 0;
}
.hide-search{ 
    color:$(main.dark.color)
}
.home #nav-search, .home .show-search, .home .hide-search {
    display:none;
}
 .show-search:hover,.hide-search:hover{
    color:$(main.color)
}
 .show-search:before{
    content:"\f002";
    font-family:FontAwesome
}
 .hide-search:before{
    content:"\f00d";
    font-family:FontAwesome
}
 #nav-search{
    display:none;
    position:absolute;
    left:0;
    top:0;
    width:100%;
    height:70px;
    z-index:99;
    background-color:$(header.bg);
    box-sizing:border-box;
    padding:0
}
 #nav-search .search-form{
    width:100%;
    height:70px;
    background-color:rgba(0,0,0,0);
    line-height:70px;
    overflow:hidden;
    padding:0
}
 #nav-search .search-input{
    width:100%;
    height:70px;
    font-family:inherit;
    color:$(main.dark.color);
    margin:0;
    padding:0 58px 0 12px;
    background-color:rgba(0,0,0,0);
    font-size:13px;
    font-weight:400;
    box-sizing:border-box;
    border:0
}
 #nav-search .search-input:focus{
    color:$(menu.color);
    outline:none
}
 .mobile-menu-toggle{
    display:none;
    position:absolute;
    top:0;
    left:0;
    width:58px;
    height:70px;
    line-height:70px;
    background-color:rgba(255,255,255,0.05);
    z-index:20;
    color:$(menu.color);
    font-size:17px;
    font-weight:400;
    text-align:center;
    cursor:pointer;
    transition:color .17s ease
}
 .mobile-menu-toggle:hover{
    color:$(menu.color)
}
 .mobile-menu-toggle:before{
    content:"\f0c9";
    font-family:FontAwesome
}
 .nav-active .mobile-menu-toggle:before{
    content:"\f00d";
    font-family:FontAwesome
}
 .overlay{
    display:none;
    position:fixed;
    top:0;
    left:0;
    right:0;
    bottom:0;
    z-index:990;
    background:rgba(255,255,255,0.8)
}
 .mobile-menu-wrap{
    display:none;
    position:absolute;
    top:70px;
    left:0;
    width:100%;
    background-color:$(submenu.bg);
    box-sizing:border-box;
    visibility:hidden;
    z-index:1000;
    opacity:0;
    transition:all .17s ease
}
 .nav-active .mobile-menu-wrap{
    visibility:visible;
    opacity:1
}
 .mobile-menu{
    position:relative;
    overflow:hidden;
    padding:20px;
    border-top:1px solid rgba(255,255,255,0.03)
}
 .mobile-menu > ul{
    margin:0
}
 .mobile-menu .m-sub{
    display:none;
    padding:0
}
 .mobile-menu ul li{
    position:relative;
    display:block;
    overflow:hidden;
    float:left;
    width:100%;
    font-size:14px;
    line-height:38px
}
 .mobile-menu > ul > li{
    font-weight:600
}
 .mobile-menu > ul li ul{
    overflow:hidden
}
 .mobile-menu ul li a{
    color:$(submenu.color);
    padding:0;
    display:block;
    transition:all .17s ease
}
 .mobile-menu ul li.has-sub .submenu-toggle{
    position:absolute;
    top:0;
    right:0;
    color:$(submenu.color);
    cursor:pointer
}
 .mobile-menu ul li.has-sub .submenu-toggle:after{
    content:'\f105';
    font-family:FontAwesome;
    font-weight:400;
    float:right;
    width:34px;
    font-size:14px;
    text-align:center;
    transition:all .17s ease
}
 .mobile-menu ul li.has-sub.show > .submenu-toggle:after{
    transform:rotate(90deg)
}
 .mobile-menu > ul > li > ul > li > a{
    color:$(submenu.color);
    opacity:.7;
    padding:0 0 0 15px
}
 .mobile-menu > ul > li > ul > li > ul > li > a{
    color:$(submenu.color);
    opacity:.7;
    padding:0 0 0 30px
}
 .home-ad .widget > .widget-title{
    display:none
}
 .home-ad .widget-content{
    float:left;
    width:728px;
    max-width:100%;
    line-height:0;
    margin:0 0 40px
}
#intro-wrap{
    display:block;
}
.home #intro-wrap {
    display:none;
    position: relative;
    float: left;
    width: 100%;
    z-index: 2;
    height: 650px;
    margin: 0;
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    background-color: #f1e7e6;
}
 #main-intro{
   position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%,-50%);
    margin: 0 auto;
    background-repeat: no-repeat;
    background-size: cover;
    background-position: center;
}
 #main-intro .widget{
    width:100%;
    display:block;
    overflow:hidden;
    z-index: 99;
    position: relative;
}
 .intro-content{
    max-width:620px;
    text-align:left;
}
 .intro-title{
    font-size:46px;
