.hero-header-search {
    position: relative;
    margin: 0 0 15px;
}
.hero-header-search .search-form{
width:100%;
height:48px;
overflow:hidden;
display:flex;
padding:0
}
.hero-header-search .search-input{
display: flex;
height:48px;
font-family:inherit;
color:#222222;
margin:0;
padding:0 10px;
background-color:#fff;
font-size:13px;
font-weight:400;
line-height:48px;
outline:none;
box-sizing:border-box;
border:0; 
    flex: 1 1 auto;
border-radius:3px 0 0 3px
}
.hero-header-search #search-submit{
width:auto;
height:48px;
background-color:$(main.color);
color:#fff;
line-height:48px;
cursor:pointer;
outline:none;
border:0;
border-radius:0 3px 3px 0;
transition:opacity .17s ease;
    display: flex;
    flex: 0 0 auto;
    padding: 0 15px;
    font-size: 18px;
    font-weight: 600;
}
.hero-header-search #search-submit:hover{
background-color:$(main.dark.color)
}
.hero-header-search ::placeholder{
color:#777
}
#main-intro .widget.LinkList{
