    font-weight: 700;
    margin: 0 0 20px;
    position: relative;
}
.service-action a {
display: inline-block;
color:$(main.color);
text-transform: none;
    border: none;
    font-weight: 600;
    font-size: 14px;
    line-height: 22px;
    padding: 0;
margin: 12px 0 0;
transition: background .17s ease;
}
.service-action a:after {
    content: '\f105';
