.toggle {
    margin-bottom: 20px;
}
.toggle:last-child {
margin:0;
}
.toggle .toggle-title {
  position: relative;
  display: block;
}
.toggle .toggle-title h3 {
  font-size: 25px;
  margin: 0px;
  line-height: 1.6;
  cursor: pointer;
  font-weight: 700;
  color:$(title.color);
text-transform:capitalize;
}

.toggle .toggle-inner {
  padding: 7px 25px 10px 25px;
  display: none;
  margin: -7px 0 6px;
  color:$(body.text.color);
}
.toggle .toggle-inner div {
  max-width: 100%;
}
.toggle .toggle-title .title-name {
  display: block;
  padding: 15px 35px 15px 25px;
box-sizing:border-box;

}
.toggle .toggle-title a i {
  font-size: 22px;
  margin-right: 5px;
}
.toggle .toggle-title i {
  position: absolute;
  background: url("data:image/svg+xml,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20viewBox%3D%220%200%2024%2048%22%20width%3D%2224%22%20height%3D%2248%22%3E%3Crect%20x%3D%2210%22%20y%3D%226%22%20width%3D%224%22%20height%3D%2212%22%20fill%3D%22%23444%22%2F%3E%3Crect%20x%3D%226%22%20y%3D%2210%22%20width%3D%2212%22%20height%3D%224%22%20fill%3D%22%23444%22%2F%3E%3Crect%20x%3D%226%22%20y%3D%2234%22%20width%3D%2212%22%20height%3D%224%22%20fill%3D%22%23444%22%2F%3E%3C%2Fsvg%3E") 0px -24px no-repeat;
  width: 24px;
  height: 24px;
  transition: all 0.3s ease;
  margin: 15px;
  right: 0;
}
.toggle .toggle-title.active i {
  background: url("data:image/svg+xml,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20viewBox%3D%220%200%2024%2048%22%20width%3D%2224%22%20height%3D%2248%22%3E%3Crect%20x%3D%2210%22%20y%3D%226%22%20width%3D%224%22%20height%3D%2212%22%20fill%3D%22%23444%22%2F%3E%3Crect%20x%3D%226%22%20y%3D%2210%22%20width%3D%2212%22%20height%3D%224%22%20fill%3D%22%23444%22%2F%3E%3Crect%20x%3D%226%22%20y%3D%2234%22%20width%3D%2212%22%20height%3D%224%22%20fill%3D%22%23444%22%2F%3E%3C%2Fsvg%3E") 0px 0px no-repeat;
}
.counter-box {
   overflow: hidden;
    margin: 0 auto 35px;
    padding: 0;
    position: relative;
}
.counter-box .container {
margin:0 auto;
}
.counter-box-info {
    float: right;
    width: 50%;
    padding-left:30px;
    box-sizing: border-box;
    display: flex;
    justify-content: center;
    align-items: center;
    justify-items: center;
}
.counter-box-info .head-text {
    text-align: left;
        margin: 0 0 30px;
}
.counter-box-image {
    float: left;
    width: 50%;
    padding-right:30px;
        box-sizing: border-box;
}
.counter-box-wrap {
float:left;
width:100%;
position:relative;
overflow:hidden;
display: grid;
    grid-template-columns: repeat(4,1fr);
    grid-gap: 20px;
    margin: 0 auto;
    border-radius:10px;
    padding:60px 0;
    background:#20262d;
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
}
.counter-box-wrap .widget {
   display: flex;
    flex-direction: column;
    width: 100%;
    padding:10px 0;
    box-sizing: border-box;
color: #fefefe;
    position: relative;
    flex-wrap: wrap;
    align-content: center;
}
.counter-avatar {
  float: left;
    margin-right: 15px;
    position: relative;
    height: 45px;
    width: 45px;
    flex-shrink: 0;
    text-align: center;
    line-height: 45px;
}
.counter-avatar img {
    width: 100%;
    height: 100%;
}
.counter-avatar i {
    display: block;
    line-height: 45px;
    font-size: 45px;
    font-weight: 400;
    font-style: normal;
    margin: 0;
    color: $(main.color);
}
.counter-info {
    overflow: hidden;
}
.counter-info .counter-title {
    font-size: 30px;
    line-height: .9;
    font-weight: 700;
    margin: 0;
    padding: 0;
}
.counter-info .counter-meta {
    font-weight: 400;
    font-size: 12px;
    color: #99A2AC;
    margin: 0;
}
.counter-box-image .counter-content {
    position: relative;
    background-size: cover;
    background-position: 50%;
    background-repeat: no-repeat;
}
.counter-image-wrap, .counter-image-wrap .widget, .counter-image-wrap .widget-content, .counter-image-wrap .counter-content {
    height: 100%;
}
#intro-author-faq-left .widget-title {
    display:none;
}
