const noThumbnail = "data:image/svg+xml,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20viewBox%3D%220%200%20160%2090%22%20preserveAspectRatio%3D%22xMidYMid%20slice%22%3E%3Crect%20width%3D%22160%22%20height%3D%2290%22%20fill%3D%22%23e5e7eb%22%2F%3E%3Ccircle%20cx%3D%2250%22%20cy%3D%2235%22%20r%3D%227%22%20fill%3D%22%239ca3af%22%2F%3E%3Cpath%20d%3D%22M20%2075L60%2045L80%2060L110%2035L150%2075Z%22%20fill%3D%22%239ca3af%22%2F%3E%3C%2Fsvg%3E";
const postPerPage = 7;
const fixedSidebar = true;
