b:includable.script:
var disqus_blogger_current_url = "";
if (!disqus_blogger_current_url.length) {
  disqus_blogger_current_url = "";
}
var disqus_blogger_homepage_url = "";
var disqus_blogger_canonical_homepage_url = "";

body.script:
//
(function () {

  // ----- Animation helpers (replace jQuery fade/slide) -----
  function fadeIn(el, ms) {
    ms = ms || 250;
    if (el._anim) clearTimeout(el._anim);
    el.style.display = '';
    el.style.opacity = '0';
    el.style.transition = 'opacity ' + ms + 'ms';
    void el.offsetWidth;  // force reflow so transition kicks in
    el.style.opacity = '1';
    el._anim = setTimeout(function () { el.style.transition = ''; }, ms);
  }
  function fadeOut(el, ms) {
    ms = ms || 250;
    if (el._anim) clearTimeout(el._anim);
    el.style.transition = 'opacity ' + ms + 'ms';
    el.style.opacity = '0';
    el._anim = setTimeout(function () {
      el.style.display = 'none';
      el.style.opacity = '';
      el.style.transition = '';
    }, ms);
  }
  function fadeToggle(el, ms) {
    if (getComputedStyle(el).display === 'none') fadeIn(el, ms);
    else fadeOut(el, ms);
  }
  function slideDown(el, ms) {
    ms = ms || 170;
    if (el._anim) clearTimeout(el._anim);
    el.style.display = '';
    var h = el.scrollHeight;
    el.style.overflow = 'hidden';
    el.style.height = '0px';
    el.style.transition = 'height ' + ms + 'ms';
    void el.offsetWidth;
    el.style.height = h + 'px';
    el._anim = setTimeout(function () {
      el.style.height = '';
      el.style.overflow = '';
      el.style.transition = '';
    }, ms);
  }
  function slideUp(el, ms) {
    ms = ms || 170;
    if (el._anim) clearTimeout(el._anim);
    el.style.overflow = 'hidden';
    el.style.height = el.scrollHeight + 'px';
    el.style.transition = 'height ' + ms + 'ms';
    void el.offsetWidth;
    el.style.height = '0px';
    el._anim = setTimeout(function () {
      el.style.display = 'none';
      el.style.height = '';
      el.style.overflow = '';
      el.style.transition = '';
    }, ms);
  }
  function slideToggle(el, ms) {
    if (getComputedStyle(el).display === 'none') slideDown(el, ms);
    else slideUp(el, ms);
  }

  function ready(fn) {
    if (document.readyState !== 'loading') fn();
    else document.addEventListener('DOMContentLoaded', fn);
  }

  ready(function () {

    // ----- Main menu: Blogger's LinkList widget renders a flat <ul>. Walk the
    //       siblings and re-parent items whose label starts with '_' (level 2)
    //       or '__' (level 3) so the CSS dropdown rules have a nested tree to
    //       hang off. The prefix underscores are stripped from the visible text.
    document.querySelectorAll('#main-menu').forEach(function (menu) {
      var nav = menu.querySelector('ul#main-menu-nav');
      if (!nav) return;
      var lastTop = null, lastSub = null;
      Array.from(nav.children).forEach(function (li) {
        if (li.tagName !== 'LI') return;
        var a = li.querySelector(':scope > a');
        if (!a) return;
        var label = a.textContent;
        var depth = 0;
        while (label.charAt(0) === '_') { depth++; label = label.substring(1); }
        if (depth === 0) { lastTop = li; lastSub = null; return; }
        a.textContent = label;
        var parent = depth === 1 ? lastTop : lastSub;
        if (!parent) return;
        var subUl = parent.querySelector(':scope > ul.sub-menu');
        if (!subUl) {
          subUl = document.createElement('ul');
          subUl.className = 'sub-menu';
          parent.appendChild(subUl);
          parent.classList.add('has-sub');
        }
        subUl.appendChild(li);
        if (depth === 1) lastSub = li;
      });
      menu.querySelectorAll('.widget').forEach(function (w) { w.classList.add('show-menu'); });
    });

    // Clone desktop nav into mobile menu container and add submenu toggles.
    var srcNav = document.getElementById('main-menu-nav');
    if (srcNav) {
      document.querySelectorAll('.mobile-menu').forEach(function (mob) {
        mob.appendChild(srcNav.cloneNode(true));
      });
    }
    document.querySelectorAll('.mobile-menu .has-sub').forEach(function (p) {
      var t = document.createElement('div');
      t.className = 'submenu-toggle';
      p.appendChild(t);
    });

    // Rewrite mega-menu top-level items to category search URLs.
    document.querySelectorAll('.mobile-menu ul > li a').forEach(function (a) {
      var classes = a.getAttribute('class') || '';
      if (/mega-menu/.test(classes)) {
        a.setAttribute('href', '/search/label/' + encodeURIComponent(a.textContent) + '?&max-results=' + postPerPage);
      }
    });

    // ----- UI toggles -----
    document.querySelectorAll('.mobile-menu-toggle').forEach(function (btn) {
      btn.addEventListener('click', function () {
        document.body.classList.toggle('nav-active');
      });
    });

    document.querySelectorAll('.mobile-menu ul li .submenu-toggle').forEach(function (toggle) {
      toggle.addEventListener('click', function (e) {
        e.preventDefault();
        var parent = toggle.parentElement;
        var sub = parent.querySelector(':scope > .sub-menu');
        parent.classList.toggle('show');
        if (sub) slideToggle(sub, 170);
      });
    });

    document.querySelectorAll('.social-toggle').forEach(function (btn) {
      btn.addEventListener('click', function () {
        document.body.classList.toggle('social-active');
        var menu = document.getElementById('social-menu');
        if (menu) fadeToggle(menu, 170);
      });
    });

    document.querySelectorAll('.show-search').forEach(function (btn) {
      btn.addEventListener('click', function () {
        document.querySelectorAll('#nav-search, .mobile-search-form').forEach(function (el) {
          fadeIn(el, 250);
          var inp = el.querySelector('input');
          if (inp) inp.focus();
        });
      });
    });
    document.querySelectorAll('.hide-search').forEach(function (btn) {
      btn.addEventListener('click', function () {
        document.querySelectorAll('#nav-search, .mobile-search-form').forEach(function (el) {
          fadeOut(el, 250);
          var inp = el.querySelector('input');
          if (inp) inp.blur();
        });
      });
    });

    // ----- Label/tag links: append max-results so paginated label pages work.
    //       Idempotent — skip if already appended (handles script re-execution).
    document.querySelectorAll('.Label a, a.b-label, a.post-tag').forEach(function (a) {
      var href = a.getAttribute('href');
      if (href && href.indexOf('max-results=') === -1) {
        a.setAttribute('href', href + '?&max-results=' + postPerPage);
      }
    });

    // ----- Author description links open in new tab.
    document.querySelectorAll('.author-description a').forEach(function (a) {
      a.setAttribute('target', '_blank');
    });

    // ----- Counter widget animation: count from 0 up to the rendered number
    //       when the element scrolls into view.
    document.querySelectorAll('.counter-info .counter-title').forEach(function (el) {
      var raw = el.textContent.trim();
      var target = parseFloat(raw.replace(/[^0-9.\-]/g, ''));
      if (!isFinite(target)) return;
      var hasComma = /,/.test(raw);
      var format = function (n) {
        var s = String(Math.round(n));
        return hasComma ? s.replace(/\B(?=(\d{3})+(?!\d))/g, ',') : s;
      };
      el.textContent = format(0);
      var observer = new IntersectionObserver(function (entries) {
        entries.forEach(function (entry) {
          if (!entry.isIntersecting) return;
          observer.disconnect();
          var duration = 3000, started = null;
          requestAnimationFrame(function tick(now) {
            if (started === null) started = now;
            var p = Math.min((now - started) / duration, 1);
            var eased = 1 - Math.pow(1 - p, 3);  // ease-out cubic
            el.textContent = format(eased * target);
            if (p < 1) requestAnimationFrame(tick);
          });
        });
      }, { threshold: 0.5 });
      observer.observe(el);
    });

    // ----- Per-post sidebar position markers: a <strike>left-sidebar</strike>,
    //       <strike>right-sidebar</strike>, or <strike>full-width</strike> inside
    //       a post body swaps the wrapper layout for that post.
    document.querySelectorAll('.post-body strike').forEach(function (el) {
      var marker = el.textContent;
      var rule = null;
      if (marker.indexOf('left-sidebar') !== -1) {
        rule = '.item #main-wrapper{float:right}.item #sidebar-wrapper{float:left}';
      } else if (marker.indexOf('right-sidebar') !== -1) {
        rule = '.item #main-wrapper{float:left}.item #sidebar-wrapper{float:right}';
      } else if (marker.indexOf('full-width') !== -1) {
        rule = '.item #main-wrapper{width:100%}.item #sidebar-wrapper{display:none}';
      }
      if (rule !== null) {
        var s = document.createElement('style');
        s.textContent = rule;
        el.parentNode.replaceChild(s, el);
      }
    });

    // ----- Sticky sidebar: posts follow as you scroll. Gated on `fixedSidebar`
    //       (defined in the Global Variables script above). Shifts the sidebar
    //       with `top:` during scroll so it stays in its column without needing
    //       a flex/grid container.
    if (typeof fixedSidebar !== 'undefined' && fixedSidebar === true) {
      var sidebar = document.getElementById('sidebar-wrapper');
      var main = document.getElementById('main-wrapper');
      if (sidebar && main) {
        var marginTop = 30, marginBottom = 30;
        sidebar.style.position = 'relative';
        var rafPending = false;
        var update = function () {
          rafPending = false;
          if (sidebar.offsetHeight >= main.offsetHeight) {
            sidebar.style.top = '';
            return;
          }
          var mainTop = main.getBoundingClientRect().top + window.scrollY;
          var maxOffset = main.offsetHeight - sidebar.offsetHeight - marginBottom;
          var scrolled = window.scrollY + marginTop - mainTop;
          sidebar.style.top = Math.max(0, Math.min(scrolled, maxOffset)) + 'px';
        };
        var schedule = function () {
          if (rafPending) return;
          rafPending = true;
          requestAnimationFrame(update);
        };
        window.addEventListener('scroll', schedule, { passive: true });
        window.addEventListener('resize', schedule);
        // Recalc on element-size change so late-loading images don't leave the
        // sticky position stale; ResizeObserver fires after layout settles.
        if (typeof ResizeObserver !== 'undefined') {
          var ro = new ResizeObserver(schedule);
          ro.observe(main);
          ro.observe(sidebar);
        } else {
          // Fallback: re-run after window load (covers most image-loading cases).
          window.addEventListener('load', schedule);
        }
        update();
      }
    }

    // ----- Back to top: show after scrolling 100px, smooth-scroll to top on click.
    //       Single scroll handler updates all .back-top buttons.
    var backTopBtns = document.querySelectorAll('.back-top');
    if (backTopBtns.length) {
      var btnVisible = false;  // .back-top starts as display:none via CSS
      window.addEventListener('scroll', function () {
        var shouldShow = window.scrollY >= 100;
        if (shouldShow === btnVisible) return;
        btnVisible = shouldShow;
        backTopBtns.forEach(function (btn) {
          if (shouldShow) fadeIn(btn, 250); else fadeOut(btn, 250);
        });
      }, { passive: true });
      backTopBtns.forEach(function (btn) {
        btn.addEventListener('click', function () {
          window.scrollTo({ top: 0, behavior: 'smooth' });
        });
      });
    }

    // ----- Helper: HTML-escape strings inserted into generated markup.
    function esc(s) {
      return String(s == null ? '' : s).replace(/[&<>"']/g, function (c) {
        return { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c];
      });
    }

    // ----- Related posts: fetch a few posts sharing the post's first label via
    //       Blogger's JSON feed and render them under .related-ready.
    document.querySelectorAll('.related-ready').forEach(function (container) {
      var tag = container.querySelector('.related-tag');
      var label = tag ? tag.getAttribute('data-label') : null;
      var count = 3;
      var feedUrl = (label && label !== 'random')
        ? '/feeds/posts/default/-/' + encodeURIComponent(label) + '?alt=json&max-results=' + (count + 1)
        : '/feeds/posts/default?alt=json&max-results=' + count + '&orderby=published';
      fetch(feedUrl).then(function (r) { return r.json(); }).then(function (data) {
        var entries = (data.feed && data.feed.entry) || [];
        var currentPath = location.pathname;
        var items = [];
        for (var i = 0; i < entries.length && items.length < count; i++) {
          var entry = entries[i];
          var alt = (entry.link || []).filter(function (l) { return l.rel === 'alternate'; })[0];
          if (!alt) continue;
          if (alt.href.indexOf(currentPath) !== -1) continue;
          var thumb = (entry['media$thumbnail'] && entry['media$thumbnail'].url) || (typeof noThumbnail !== 'undefined' ? noThumbnail : '');
          // Bump default 72px thumbnail up to a usable size for the 120px block.
          thumb = thumb.replace(/\/s72-c\//, '/w320-h180-p-k-no-nu/');
          items.push({
            url: alt.href,
            title: (entry.title && entry.title.$t) || '',
            thumb: thumb,
          });
        }
        if (!items.length) { container.innerHTML = ''; return; }
        container.innerHTML =
          '<ul class="related-posts">' +
          items.map(function (it) {
            return '<li class="related-item">' +
                     '<a class="post-image-link" href="' + esc(it.url) + '">' +
                       '<img class="post-thumb" loading="lazy" src="' + esc(it.thumb) + '" alt="' + esc(it.title) + '"/>' +
                     '</a>' +
                     '<h4 class="post-title"><a href="' + esc(it.url) + '">' + esc(it.title) + '</a></h4>' +
                   '</li>';
          }).join('') +
          '</ul>';
      }).catch(function () { container.innerHTML = ''; });
    });

    // ----- Post navigation: fetch the prev/next post pages and extract their
    //       titles so the nav links can show what's coming/going. Uses
    //       DOMParser (no script execution) and only sets .textContent — no
    //       HTML injection — so the fetched HTML can't introduce DOM nodes.
    document.querySelectorAll('.post-nav').forEach(function (nav) {
      [
        { linkSel: '.prev-post-link', target: '.post-prev a .post-nav-inner p' },
        { linkSel: '.next-post-link', target: '.post-next a .post-nav-inner p' },
      ].forEach(function (cfg) {
        var link = nav.querySelector(cfg.linkSel) || document.querySelector(cfg.linkSel);
        var href = link ? link.getAttribute('href') : null;
        if (!href) return;
        fetch(href).then(function (r) { return r.text(); }).then(function (html) {
          var doc = new DOMParser().parseFromString(html, 'text/html');
          var titleEl = doc.querySelector('.blog-post h1.post-title');
          if (!titleEl) return;
          var targetEl = nav.querySelector(cfg.target) || document.querySelector(cfg.target);
          if (targetEl) targetEl.textContent = titleEl.textContent.trim();
        }).catch(function () { /* leave placeholder text as-is */ });
      });
    });

  });
})();
//

b:if.script:
//
// Pagination state. Globals are intentional — inline onclick handlers in the
// rendered pager need to call getPage/getLabelPage.
let postResults = postPerPage;
let numOfPages = 2;
const pageOf = ["Page", "of"];
let noPage;
let currentPage;
let currentPageNo;
let postLabel;
const HOME = "/";

function buildLabelHref(page) {
  return `/search/label/${postLabel}?&max-results=${postResults}` + (page ? `#PageNo=${page}` : '');
}

function startPagination(totalResults) {
  const half = Math.floor(numOfPages / 2);
  if (half === numOfPages - half) numOfPages = half * 2 + 1;
  let pageStart = currentPageNo - half;
  if (pageStart < 1) pageStart = 1;
  let lastPageNo = Math.floor(totalResults / postResults) + 1;
  if (lastPageNo - 1 === totalResults / postResults) lastPageNo -= 1;
  let pageEnd = pageStart + numOfPages - 1;
  if (pageEnd > lastPageNo) pageEnd = lastPageNo;

  const parts = [];
  parts.push(`<span class="page-of">${pageOf[0]} ${currentPageNo} ${pageOf[1]} ${lastPageNo}</span>`);

  const prev = Number(currentPageNo) - 1;
  if (currentPageNo > 1) {
    if (Number(currentPageNo) === 2) {
      const href = currentPage === 'page' ? HOME : `/search/label/${postLabel}?&max-results=${postResults}`;
      parts.push(`<a class="page-num page-prev" href="${href}"></a>`);
    } else {
      const fn = currentPage === 'page' ? 'getPage' : 'getLabelPage';
      parts.push(`<a class="page-num page-prev" href="#" onclick="${fn}(${prev});return false"></a>`);
    }
  }

  if (pageStart > 1) {
    const href = currentPage === 'page' ? HOME : `/search/label/${postLabel}?&max-results=${postResults}`;
    parts.push(`<a class="page-num" href="${href}">1</a>`);
  }
  if (pageStart > 2) parts.push('<span class="page-num page-dots">...</span>');

  for (let d = pageStart; d <= pageEnd; d++) {
    if (Number(currentPageNo) === d) {
      parts.push(`<span class="page-num page-active">${d}</span>`);
    } else if (d === 1) {
      const href = currentPage === 'page' ? HOME : `/search/label/${postLabel}?&max-results=${postResults}`;
      parts.push(`<a class="page-num" href="${href}">1</a>`);
    } else {
      const fn = currentPage === 'page' ? 'getPage' : 'getLabelPage';
      parts.push(`<a class="page-num" href="#" onclick="${fn}(${d});return false">${d}</a>`);
    }
  }

  if (pageEnd < lastPageNo - 1) parts.push('<span class="page-num page-dots">...</span>');
  if (pageEnd < lastPageNo) {
    const fn = currentPage === 'page' ? 'getPage' : 'getLabelPage';
    parts.push(`<a class="page-num" href="#" onclick="${fn}(${lastPageNo});return false">${lastPageNo}</a>`);
  }

  const next = Number(currentPageNo) + 1;
  if (currentPageNo < lastPageNo) {
    const fn = currentPage === 'page' ? 'getPage' : 'getLabelPage';
    parts.push(`<a class="page-num page-next" href="#" onclick="${fn}(${next});return false"></a>`);
  }

  const html = parts.join('');
  const areas = document.querySelectorAll('[name="pageArea"]');
  const pager = document.getElementById('blog-pager');
  areas.forEach(area => { area.innerHTML = html; });
  if (pager && areas.length === 0) pager.innerHTML = html;
}

function dataFeed(data) {
  const total = parseInt(data.feed.openSearch$totalResults.$t, 10);
  startPagination(total);
}

function pageCurrentBlogger() {
  const url = location.href;
  if (url.indexOf('/search/label/') !== -1) {
    const labelStart = url.indexOf('/search/label/') + 14;
    const labelEnd = url.indexOf('?updated-max') !== -1 ? url.indexOf('?updated-max') : url.indexOf('?&max');
    postLabel = url.substring(labelStart, labelEnd);
  }
  if (url.indexOf('?q=') !== -1 || url.indexOf('.html') !== -1) return;

  const pageNoIdx = url.indexOf('#PageNo=');
  currentPageNo = pageNoIdx !== -1 ? url.substring(pageNoIdx + 8) : 1;

  if (url.indexOf('/search/label/') === -1) {
    currentPage = 'page';
    fetchFeed(`${HOME}feeds/posts/summary?max-results=1&alt=json`).then(dataFeed);
  } else {
    currentPage = 'label';
    if (url.indexOf('&max-results=') === -1) postResults = 20;
    fetchFeed(`${HOME}feeds/posts/summary/-/${postLabel}?alt=json&max-results=1`).then(dataFeed);
  }
}

function fetchFeed(url) {
  return fetch(url).then(r => r.json());
}

function getPage(page) {
  const jsonstart = (page - 1) * postResults;
  noPage = page;
  fetchFeed(`${HOME}feeds/posts/summary?start-index=${jsonstart}&max-results=1&alt=json`).then(findPostDate);
}

function getLabelPage(page) {
  const jsonstart = (page - 1) * postResults;
  noPage = page;
  fetchFeed(`${HOME}feeds/posts/summary/-/${postLabel}?start-index=${jsonstart}&max-results=1&alt=json`).then(findPostDate);
}

function findPostDate(data) {
  const post = data.feed.entry[0];
  const ts = encodeURIComponent(post.published.$t.substring(0, 19) + post.published.$t.substring(23, 29));
  const url = currentPage === 'page'
    ? `/search?updated-max=${ts}&max-results=${postResults}#PageNo=${noPage}`
    : `/search/label/${postLabel}?updated-max=${ts}&max-results=${postResults}#PageNo=${noPage}`;
  location.href = url;
}

pageCurrentBlogger();
//
